export default {
  data: function data() {
    return {
      dialogVisible: false,
      loading: false,
      form: {
        title: '',
        content: ''
      },
      rules: {
        title: [{
          required: true,
          message: '请输入公告标题',
          trigger: 'blur'
        }, {
          min: 2,
          max: 100,
          message: '长度在 2 到 100 个字符',
          trigger: 'blur'
        }],
        content: [{
          required: true,
          message: '请输入公告内容',
          trigger: 'blur'
        }, {
          min: 5,
          max: 500,
          message: '长度在 5 到 500 个字符',
          trigger: 'blur'
        }]
      }
    };
  },
  methods: {
    submitForm: function submitForm() {
      var _this = this;

      this.$refs.form.validate(function (valid) {
        if (valid) {
          _this.loading = true;

          _this.$http.post('api/communityCtl/addNotice', _this.form).then(function (resp) {
            _this.loading = false;

            if (resp.data.code === 200) {
              _this.$message.success('新增成功');

              _this.closeDialog();

              _this.$emit('refresh');
            } else {
              _this.$message.error(resp.data.message || '新增失败');
            }
          }).catch(function () {
            _this.loading = false;

            _this.$message.error('新增失败，请稍后重试');
          });
        }
      });
    },
    closeDialog: function closeDialog() {
      this.dialogVisible = false;
      this.$refs.form.resetFields();
      this.form = {
        title: '',
        content: ''
      };
    }
  }
};
